INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('retired-7fec267e-moex-00146', 'retired-7fec267e', 'retired-7fec267e-moex-112-b96fcbef', 'sub-retired-7fec267e-08', NULL, 'essay', '甲因精神障礙經聲請而受輔助宣告，法院選定其兄乙擔任輔助人。其父
死亡遺有土地 A、B 兩筆，甲辦理繼承登記，是否應經輔助人乙之同意？
另甲未經乙之同意，將其 C屋出售並移轉登記給丙，輔助人乙得否請求
丙返還該屋給甲？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:01+00:00", "source_pdf_sha1": "8ea67f012d8e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "131", "s": "0804", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則與刑法總則", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "一般行政"}'::jsonb, NULL),
  ('retired-7fec267e-moex-00147', 'retired-7fec267e', 'retired-7fec267e-moex-112-b96fcbef', 'sub-retired-7fec267e-08', NULL, 'essay', '甲為 A 車所有人，其子乙未經甲同意，於 7 月 1 日先將 A 車出售給
丙，兩人另訂租約由乙繼續占有使用 A 車，使丙取得間接占有以代交
付。7 月 15日，乙將 A車送至維修廠委請丁修理，卻拒絕清償所積欠修
理費，丁依法行使留置權。嗣後 7 月 31 日甲死亡，乙因繼承而取得 A
車所有權。試問：乙將 A車讓與丙之法律行為效力如何？丙何時取得 A
車所有權？丁修理 A 車所取得的留置權是否因甲死亡而受影響？請援
引法律依據說明之。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:01+00:00", "source_pdf_sha1": "8ea67f012d8e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "131", "s": "0804", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則與刑法總則", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "一般行政"}'::jsonb, NULL),
  ('retired-7fec267e-moex-00148', 'retired-7fec267e', 'retired-7fec267e-moex-112-b96fcbef', 'sub-retired-7fec267e-08', NULL, 'essay', '兄弟甲乙兩人因好賭成性，急需賭資，各自決意害死他們的父親丙，以
期早日繼承遺產。某日甲、乙兩人各自在丙飲用的咖啡內放置不同毒藥，
甲乙彼此不知對方也下毒。丙喝完咖啡後，立即死亡。經法醫鑑定後，
確認甲乙兩人各自投放的毒藥劑量單獨均足以致人於死。試問甲、乙之
刑事責任為何？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:01+00:00", "source_pdf_sha1": "8ea67f012d8e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "131", "s": "0804", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則與刑法總則", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "一般行政"}'::jsonb, NULL),
  ('retired-7fec267e-moex-00149', 'retired-7fec267e', 'retired-7fec267e-moex-112-b96fcbef', 'sub-retired-7fec267e-08', NULL, 'essay', '甲出資唆使乙將丙殺害，乙應允，甲交付給乙一張丙的生活照。某日夜
晚，乙見丙出門跑步，遂埋伏在暗處槍擊之，乙見丙應聲倒地後迅速離
開現場。實際上倒地死亡者並非為丙，而是身形與丙非常近似的丁。試
問甲、乙應負何刑責？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:01+00:00", "source_pdf_sha1": "8ea67f012d8e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "131", "s": "0804", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則與刑法總則", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "一般行政"}'::jsonb, NULL),
  ('retired-7fec267e-moex-00150', 'retired-7fec267e', 'retired-7fec267e-moex-112-3d2b73b6', 'sub-retired-7fec267e-04', NULL, 'single_choice', '1 考 試 別：一般警察人員考試、鐵路人員考試、退除役軍人轉任公務人員考試 類科組別：各類別、各類科', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:01+00:00", "source_pdf_sha1": "87de1eee000f", "answer_pdf_sha1": "3e2ca2064eed", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "131", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "一般行政"}'::jsonb, NULL),
  ('retired-7fec267e-moex-00151', 'retired-7fec267e', 'retired-7fec267e-moex-112-3d2b73b6', 'sub-retired-7fec267e-04', NULL, 'single_choice', '有關法治國原則，下列敘述何者正確？', '["大法官迄今尚未承認法治國原則為我國憲法基本原則", "地方政府限制人民之自由權利，若屬地方自治事項，即無法治國原則之適用", "法治國原則要求，立法者制定法律時，不得在法律中使用不確定法律概念", "司法機關行使司法權，亦受法治國原則拘束"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:01+00:00", "source_pdf_sha1": "87de1eee000f", "answer_pdf_sha1": "3e2ca2064eed", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "131", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "一般行政"}'::jsonb, NULL),
  ('retired-7fec267e-moex-00152', 'retired-7fec267e', 'retired-7fec267e-moex-112-3d2b73b6', 'sub-retired-7fec267e-04', NULL, 'single_choice', '下列何種事項，憲法或增修條文並無明文規定以法律定之？', '["外交", "創制、複決兩權之行使", "國防之組織", "原住民族之地位及政治參與"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:01+00:00", "source_pdf_sha1": "87de1eee000f", "answer_pdf_sha1": "3e2ca2064eed", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "131", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "一般行政"}'::jsonb, NULL),
  ('retired-7fec267e-moex-00153', 'retired-7fec267e', 'retired-7fec267e-moex-112-3d2b73b6', 'sub-retired-7fec267e-04', NULL, 'single_choice', '依司法院大法官解釋，關於人民應考試服公職之權，下列敘述何者錯誤？', '["應考試、服公職分別為兩種權利", "應考試服公職之權為廣義之參政權", "專門職業及技術人員因非公務人員，其應考試權不受憲法保障", "人民服公職之權受侵害，得提起行政爭訟以為救濟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:01+00:00", "source_pdf_sha1": "87de1eee000f", "answer_pdf_sha1": "3e2ca2064eed", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "131", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "一般行政"}'::jsonb, NULL),
  ('retired-7fec267e-moex-00154', 'retired-7fec267e', 'retired-7fec267e-moex-112-3d2b73b6', 'sub-retired-7fec267e-04', NULL, 'single_choice', '集會遊行法第8條規定，室外集會、遊行，應向主管機關申請許可。但宗教、民俗、婚、喪、喜、慶活動 等不在此限，不涉及下列何種基本權利？', '["集會自由", "信仰自由", "宗教自由", "遷徙自由"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:01+00:00", "source_pdf_sha1": "87de1eee000f", "answer_pdf_sha1": "3e2ca2064eed", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "131", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "一般行政"}'::jsonb, NULL),
  ('retired-7fec267e-moex-00155', 'retired-7fec267e', 'retired-7fec267e-moex-112-3d2b73b6', 'sub-retired-7fec267e-04', NULL, 'single_choice', '依司法院大法官解釋意旨，有關徵收補償，下列敘述何者錯誤？', '["徵收之補償應儘速發給，否則徵收土地核准案即應失其效力", "直轄市或縣（市）政府事後發現原發給之補償費短少，得自由裁量是否撤銷原補償處分", "補償應合理、相當", "區段徵收制度中，以徵收後可供建築之抵價地折算抵付補償費，屬徵收補償方式之一種"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:01+00:00", "source_pdf_sha1": "87de1eee000f", "answer_pdf_sha1": "3e2ca2064eed", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "131", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "一般行政"}'::jsonb, NULL)
